import React, { useState } from "react";

import ChatBox from "./components/ChatBox";
import Selects from "./components/seletorIAS";
import PerguntaResposta from "./components/PerguntaResposta";
import Header from "./header";

import { prepararPergunta } from "./utils/manipulacoesString";
import {
  chamarChatGPT,
  chamarGemini,
  chamarGrok,
  chamarDeepseek,
} from "./utils/APIchats";

import "./App.css";

import ModalConfig from "./components/ModalConfig";
import ModalFeedback from "./components/modalFeedback";

export default function App() {
  const [IA1, setIA1] = React.useState("");
  const [IA2, setIA2] = React.useState("");
  const [arbitro, setArbitro] = React.useState("");

  const [open, isOpen] = useState(false);
  const [openFeedback, setOpenFeedback] = useState(false);

  const [pergunta, setPergunta] = React.useState("");
  const [resposta, setResposta] = React.useState("");
  const [respostaArbitro, setRespostaArbitro] = React.useState("");
  const [trocarVerdadeiro, setTrocarVerdadeiro] = React.useState(false);
  const [respostaIA1, setRespostaIA1] = React.useState("");
  const [respostaIA2, setRespostaIA2] = React.useState("");

  const [prefixo, setPrefixo] = React.useState(
    "responda como se fosse um estudante do ensino medio tecnico, em ate 5 linhas, sem girias antigas, com tom humanizado, sem girias e sem emojis para a seguinte pergunta: ",
  );

  const [, setPrefixoArbitro] = React.useState("");
  const [feedback, setFeedback] = React.useState("");

  const todasIASResponderam =
    respostaIA1.trim() && respostaIA2.trim() && respostaArbitro.trim();

  const funcoesIA = {
    Grok: (perguntaMontada, isArbiter) => chamarGrok(perguntaMontada, isArbiter),
    Gemini: (perguntaMontada, isArbiter) =>
      chamarGemini(perguntaMontada, isArbiter),
    Chatgpt: (perguntaMontada, isArbiter) =>
      chamarChatGPT(perguntaMontada, isArbiter),
    deepseek: (perguntaMontada, isArbiter) =>
      chamarDeepseek(perguntaMontada, isArbiter),
  };

  async function chamarFuncaoPorNome(nome, perguntaPreparada, isArbiter = false) {
    const funcaoSelecionada = funcoesIA[nome];
    if (!funcaoSelecionada) {
      throw new Error(`IA nao suportada: ${nome}`);
    }

    const respostaAPI = await funcaoSelecionada(perguntaPreparada, isArbiter);
    return respostaAPI?.resp || "";
  }

  async function fluxoComunicacao() {
    if (!IA1 || !IA2 || !arbitro) {
      alert("Por favor selecione todas as IAs e o arbitro");
      return;
    }

    try {
      const perguntaPreparada = prepararPergunta(pergunta, prefixo);

      const respostaPrimeiraIA = await chamarFuncaoPorNome(
        IA1,
        perguntaPreparada,
        false,
      );
      const respostaSegundaIA = await chamarFuncaoPorNome(
        IA2,
        perguntaPreparada,
        false,
      );

      setRespostaIA1(respostaPrimeiraIA);
      setRespostaIA2(respostaSegundaIA);

      let textoArbitro =
        pergunta +
        " Resposta primeira IA: " +
        respostaPrimeiraIA +
        " Resposta segunda IA: " +
        respostaSegundaIA;

      if (resposta.trim()) {
        textoArbitro += " Resposta do usuario: " + resposta;
      }

      textoArbitro +=
        " verifique se existe algum erro, alucinacoes ou falta de informacoes nas respostas das IAs e faca uma analise curta em ate 20 linhas";

      setPrefixoArbitro(textoArbitro);

      const respostaFinalArbitro = await chamarFuncaoPorNome(
        arbitro,
        textoArbitro,
        true,
      );
      setRespostaArbitro(respostaFinalArbitro);
      setFeedback("");
    } catch (erro) {
      console.error("Erro no fluxo de comunicacao:", erro);
      alert("Ocorreu um erro ao consultar as IAs. Tente novamente.");
    }
  }

  function salvarEmArquivo() {
    if (!pergunta || !respostaIA1 || !respostaIA2 || !respostaArbitro) {
      alert("Por favor envie a pergunta primeiro");
      return;
    }

    const conteudo = `PERGUNTA:\n${pergunta}\n\n${resposta ? `RESPOSTA DO USUARIO:\n${resposta}\n\n` : ""}RESPOSTA IA 1 (${IA1}):\n${respostaIA1}\n\nRESPOSTA IA 2 (${IA2}):\n${respostaIA2}\n\nANALISE DO ARBITRO (${arbitro}):\n${respostaArbitro}${feedback ? `\n\nFEEDBACK:\n${feedback}` : ""}\n\n${"=".repeat(50)}\nData: ${new Date().toLocaleString("pt-BR")}`;

    const elemento = document.createElement("a");
    const arquivo = new Blob([conteudo], { type: "text/plain" });
    const objectURL = URL.createObjectURL(arquivo);
    elemento.href = objectURL;
    elemento.download = `feedback_${Date.now()}.txt`;
    document.body.appendChild(elemento);
    elemento.click();
    document.body.removeChild(elemento);
    URL.revokeObjectURL(objectURL);

    alert("Arquivo salvo com sucesso");
  }

  return (
    <div>
      <ModalConfig
        className="ModalApp"
        mudarPergunta={setPrefixo}
        open={open}
        close={() => isOpen(false)}
      ></ModalConfig>

      <div className="caixa">
        <Header abrirModal={() => isOpen(true)} />
        <div className="caixaPrincipal">
          <ChatBox resp={respostaArbitro} />

          <Selects
            id=""
            IA1={IA1}
            IA2={IA2}
            arbitro={arbitro}
            trocarIA1={setIA1}
            trocarIA2={setIA2}
            trocarArbitro={setArbitro}
          />
        </div>

        {todasIASResponderam && (
          <button className="feedbackBtn" onClick={() => setOpenFeedback(true)}>
            Dar Feedback e salvar
          </button>
        )}

        <ModalFeedback
          className="ModalApp"
          open={openFeedback && todasIASResponderam}
          setOpenFeedback={setOpenFeedback}
          feedback={feedback}
          setFeedback={setFeedback}
          salvarEmArquivo={salvarEmArquivo}
        ></ModalFeedback>

        <PerguntaResposta
          id=""
          quest={pergunta}
          answer={resposta}
          setquest={setPergunta}
          setanswer={setResposta}
          checkbox={trocarVerdadeiro}
          bloquearResposta={setTrocarVerdadeiro}
          fluxoComunicacao={fluxoComunicacao}
        />
      </div>
    </div>
  );
}
